previewCss:
.darma-loader-darma-custom-309 {
  color: var(--loader-color, #e11d48);
  height: 54px;
  aspect-ratio: 2;
  border-bottom: 3px solid var(--loader-secondary-color, #fb7185);
  position: relative;
  overflow: hidden;
}
.darma-loader-darma-custom-309:before {
  content: "";
  position: absolute;
  inset: auto 42.5% 0;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #e11d48);
  animation: 
    darma-loader-darma-custom-309-l2-0 .5s cubic-bezier(0,900,1,900) infinite,
    darma-loader-darma-custom-309-l2-1  2s linear infinite alternate;
}
@keyframes darma-loader-darma-custom-309-l2-0 {
  0%,2% {bottom: 0%}
  98%,to {bottom:.1%}
}
@keyframes darma-loader-darma-custom-309-l2-1 {
  0% {translate: -500%}
  to {translate:  500%}
}

